const generatePDF = async () => {
    if (!briefDiagnosis || !detailedDiagnosis) return;
    const doc = new jsPDF();

    // Header with green background and text
    doc.setFillColor(0, 128, 0); // Green
    doc.rect(0, 0, 210, 20, 'F');
    doc.setFontSize(20);
    doc.setTextColor(255);
    doc.text('Plant Diagnosis Report', 10, 15);

    // Plant Information
    doc.setFontSize(16);
    doc.setTextColor(0);
    doc.text(`Plant Name: ${plantName}`, 10, 30);
    doc.text(`Plant Health: ${plantHealth}`, 10, 40);

    // Add Image - Asynchronous Image Loading
    return new Promise<void>((resolve, reject) => {
        const img = new Image();
        img.crossOrigin = 'Anonymous'; // Required for cross-origin images
        img.onload = () => {
            try {
                // Adjust image dimensions as needed
                const imgWidth = 80;
                const imgHeight = 80;
                doc.addImage(img, 'JPEG', 10, 50, imgWidth, imgHeight);

                // Diagnosis and Detailed Info (adjust positions as needed)
                doc.text(`Brief Diagnosis: ${briefDiagnosis}`, 10, 140);
                doc.text(`Detailed Info: ${detailedDiagnosis}`, 10, 160);

                doc.save('plant_diagnosis.pdf');
                resolve();
            } catch (error) {
                console.error("Error adding image:", error);
                reject(error);
            }
        };
        img.onerror = (error) => {
            console.error("Error loading image:", error);
            reject(error);
        };
        img.src = imagePreview; // 'imagePreview' is assumed to be a URL/blob of the plant image
    });
};
